import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.kxxRO88J.js";const m=JSON.parse('{"title":"왜 Codex인가","description":"","frontmatter":{"sidebar_position":3},"headers":[],"relativePath":"01-intro/why-ai-agents.md","filePath":"01-intro/why-ai-agents.md"}'),i={name:"01-intro/why-ai-agents.md"};function n(d,e,p,l,c,r){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="왜-codex인가" tabindex="-1">왜 Codex인가 <a class="header-anchor" href="#왜-codex인가" aria-label="Permalink to &quot;왜 Codex인가&quot;">​</a></h1><h2 id="codex가-특별한-이유" tabindex="-1">Codex가 특별한 이유 <a class="header-anchor" href="#codex가-특별한-이유" aria-label="Permalink to &quot;Codex가 특별한 이유&quot;">​</a></h2><p>AI 에이전트를 이미 사용하고 있다면 &quot;왜 Codex여야 하는가? Claude Code로도 되지 않는가?&quot;라는 의문이 생길 수 있습니다. 결론부터 말씀드리면, <strong>Codex와 Claude Code 둘 다 Remotion 프로젝트에서 사용할 수 있습니다</strong>. 이 블로그는 주로 Codex CLI를 기준으로 설명하지만, Claude Code를 선호하신다면 동일한 워크플로우가 적용됩니다.</p><p>그러나 Remotion 생태계는 특히 Codex에 최적화된 도구들을 제공하고 있으며, 그것이 Codex를 기준점으로 삼는 이유입니다.</p><h2 id="remotion-agent-skills" tabindex="-1">Remotion Agent Skills <a class="header-anchor" href="#remotion-agent-skills" aria-label="Permalink to &quot;Remotion Agent Skills&quot;">​</a></h2><p>Remotion 팀은 Codex를 위한 28개의 전용 스킬 모듈을 공개했습니다. 다음 명령어 하나로 설치됩니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remotion-dev/skills</span></span></code></pre></div><p>이 명령어를 실행하면 프로젝트의 <code>.claude/skills/</code> 디렉토리에 28개의 규칙 파일이 설치됩니다. 각 모듈은 Codex가 Remotion 코드를 생성할 때 지켜야 할 규칙과 패턴을 정의합니다.</p><p>스킬 모듈이 다루는 주요 영역은 다음과 같습니다.</p><table tabindex="0"><thead><tr><th>스킬 모듈</th><th>역할</th></tr></thead><tbody><tr><td><code>remotion-core-concepts</code></td><td><code>useCurrentFrame</code>, <code>interpolate</code>, <code>spring</code> 올바른 사용법</td></tr><tr><td><code>remotion-composition</code></td><td>컴포지션 등록 및 <code>Root.tsx</code> 구성</td></tr><tr><td><code>remotion-transitions</code></td><td><code>&lt;TransitionSeries&gt;</code> 사용 규칙</td></tr><tr><td><code>remotion-audio</code></td><td><code>&lt;Audio&gt;</code> 배치 규칙 (TransitionSeries 외부에 배치)</td></tr><tr><td><code>remotion-elevenlabs-voiceover</code></td><td>ElevenLabs TTS 파일 생성 자동화</td></tr><tr><td><code>remotion-captions</code></td><td><code>@remotion/captions</code> 자막 동기화</td></tr><tr><td><code>remotion-lambda</code></td><td>AWS Lambda 렌더링 설정</td></tr><tr><td><code>remotion-shapes</code></td><td><code>@remotion/shapes</code> 도형 애니메이션</td></tr></tbody></table><p>스킬이 없는 일반 AI는 Remotion 코드를 생성할 때 CSS 애니메이션(<code>@keyframes</code>)을 사용하거나, <code>&lt;Audio&gt;</code>를 <code>&lt;TransitionSeries&gt;</code> 내부에 잘못 배치하는 등의 오류를 범합니다. 스킬 모듈은 이러한 실수를 사전에 방지합니다.</p><h2 id="remotion-documentation-mcp" tabindex="-1">Remotion Documentation MCP <a class="header-anchor" href="#remotion-documentation-mcp" aria-label="Permalink to &quot;Remotion Documentation MCP&quot;">​</a></h2><p>Codex에 Remotion 공식 문서를 직접 연결할 수 있습니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remotion-documentation</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @remotion/mcp@latest</span></span></code></pre></div><p>이 MCP 서버는 Codex가 코드를 생성할 때마다 Remotion의 최신 API 문서를 실시간으로 참조하도록 합니다. 모델의 학습 데이터 컷오프 이후 업데이트된 API 변경사항도 반영되므로, 구버전 패턴을 생성하는 문제를 방지할 수 있습니다.</p><p>설치 확인:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p>출력에 <code>remotion-documentation</code>이 보이면 정상입니다.</p><h2 id="vibe-coding-이란-무엇인가" tabindex="-1">&quot;Vibe Coding&quot;이란 무엇인가 <a class="header-anchor" href="#vibe-coding-이란-무엇인가" aria-label="Permalink to &quot;&quot;Vibe Coding&quot;이란 무엇인가&quot;">​</a></h2><p>&quot;Vibe coding&quot;은 코드의 세부 구현보다 원하는 결과물의 분위기(vibe)를 자연어로 설명하고, AI가 나머지를 처리하게 하는 방식입니다. 오픈소스 프로젝트 <a href="https://github.com/GurYN/vibe-motion" target="_blank" rel="noreferrer">Vibe Motion</a>이 이 접근법을 Remotion에 적용한 대표적인 예입니다.</p><p>실제 사례를 보면 이해하기 쉽습니다.</p><p><strong>전통적인 방식:</strong></p><ol><li>Remotion API 문서를 읽는다</li><li><code>interpolate()</code> 파라미터를 찾아본다</li><li>TypeScript 코드를 직접 작성한다</li><li>오류를 수정한다</li><li>결과를 확인한다</li></ol><p><strong>Vibe coding 방식:</strong></p><ol><li>Codex에게 원하는 것을 설명한다</li><li>결과를 확인하고 수정 방향을 피드백한다</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 실제 Codex 프롬프트 예시</span></span>
<span class="line"><span>&quot;1920x1080 영상에 흰 배경에서 파란색 제목 텍스트가</span></span>
<span class="line"><span>아래에서 올라오며 페이드인되는 씬을 만들어줘.</span></span>
<span class="line"><span>텍스트는 &#39;TechFlow — 업무를 자동화하다&#39;이고</span></span>
<span class="line"><span>폰트 크기는 72px, 애니메이션은 0.5초 동안.&quot;</span></span></code></pre></div><p>이 한 문장으로 Codex는 올바른 TypeScript 컴포넌트를 생성합니다.</p><h2 id="codex-cli-vs-claude-code" tabindex="-1">Codex CLI vs Claude Code <a class="header-anchor" href="#codex-cli-vs-claude-code" aria-label="Permalink to &quot;Codex CLI vs Claude Code&quot;">​</a></h2><p>실무에서는 둘 중 더 편한 도구를 선택하시면 됩니다. 주요 차이점은 다음과 같습니다.</p><table tabindex="0"><thead><tr><th>항목</th><th>Codex CLI</th><th>Claude Code</th></tr></thead><tbody><tr><td>설치</td><td><code>npm install -g @openai/codex</code></td><td><code>npm install -g @anthropic-ai/claude-code</code></td></tr><tr><td>Remotion 스킬</td><td>공식 지원 (<code>npx skills add remotion-dev/skills</code>)</td><td>동일한 스킬 파일 활용 가능</td></tr><tr><td>MCP 연동</td><td><code>codex mcp add</code></td><td>MCP 서버 연동</td></tr><tr><td>모델</td><td>GPT-4o, o1, o3</td><td>Claude 3.5 Sonnet, Opus</td></tr></tbody></table><p>이 블로그의 코드 예제는 Codex CLI를 기준으로 작성되어 있지만, Claude Code를 사용하는 경우 프롬프트 자체는 동일하게 사용할 수 있습니다.</p><h2 id="이-블로그에서-배울-워크플로우" tabindex="-1">이 블로그에서 배울 워크플로우 <a class="header-anchor" href="#이-블로그에서-배울-워크플로우" aria-label="Permalink to &quot;이 블로그에서 배울 워크플로우&quot;">​</a></h2><p>다음 챕터부터 실습할 워크플로우의 전체 흐름입니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 프로젝트 생성 (bun create video)</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>2. Codex + Remotion 스킬 장착</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>3. 자연어 프롬프트로 모션 그래픽 생성</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>4. ElevenLabs로 AI 보이스오버 생성</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>5. Codex로 오디오 동기화 자동화</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>6. npx remotion render로 MP4 출력</span></span></code></pre></div><p>각 단계에서 Codex가 코드를 생성하고, 여러분은 결과물을 검토하고 방향을 수정하는 역할을 합니다. Remotion 내부 코드를 모두 이해하지 않아도 실용적인 영상을 만들 수 있는 것이 이 접근법의 핵심입니다.</p><hr><p><a href="./../02-setup/">2장. 환경 설정 →</a></p>`,37)])])}const u=t(i,[["render",n]]);export{m as __pageData,u as default};
